class Solution:
    def wonderfulSubstrings(self, word):
        n = len(word)
        if n > 600:
            from collections import defaultdict
            counts = defaultdict(int)
            counts[0] = 1
            mask = 0
            total = 0
            for ch in word:
                mask ^= 1 << (ord(ch) - 97)
                total += counts[mask]
                for b in range(10):
                    total += counts[mask ^ (1 << b)]
                counts[mask] += 1
            return total
        total = 0
        for i in range(n):
            cnt = [0] * 10
            for j in range(i, n):
                cnt[ord(word[j]) - 97] ^= 1
                if sum(cnt) <= 1:
                    total += 1
        return total

