var wonderfulSubstrings = function(word) {
    const counts = new Array(1024).fill(0);
    counts[0] = 1;
    let mask = 0;
    let total = 0;
    for (let i = 0; i < word.length; i++) {
        mask ^= 1 << (word.charCodeAt(i) - 97);
        total += counts[mask];
        for (let b = 0; b < 10; b++) total += counts[mask ^ (1 << b)];
        counts[mask] += 1;
    }
    return total;
};
